/**
 * Email channel handler — listens for notification events and delivers via email.
 *
 * This is one channel in the notification system. Additional channels (SMS, push,
 * in-app) can be added by creating similar handlers that subscribe to the same
 * 'notification:requested' event on the EventBus.
 *
 * Depends on:
 * - EventBus (event system) for receiving notification events
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationRequestedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface DeliveredEmail {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  deliveredAt: Date;
}

let nextEmailId = 1;

function generateEmailId(): string {
  return `email-${String(nextEmailId++).padStart(4, '0')}`;
}

export function resetEmailIdCounter(): void {
  nextEmailId = 1;
}

export class EmailChannelHandler {
  private logger = new Logger('EmailChannelHandler');
  private deliveredEmails: DeliveredEmail[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>(
      'notification:requested',
      (event) => this.handleNotification(event),
    );
  }

  /**
   * Handle a notification event by delivering it as an email.
   */
  private handleNotification(event: NotificationRequestedEvent): void {
    if (event.channel !== 'email') {
      return;
    }

    const email: DeliveredEmail = {
      id: generateEmailId(),
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      deliveredAt: new Date(),
    };

    this.deliveredEmails.push(email);
    this.logger.info(`Email delivered: ${email.id} to ${email.recipient}`);
  }

  /**
   * Get all delivered emails.
   */
  getDeliveredEmails(): DeliveredEmail[] {
    return [...this.deliveredEmails];
  }

  /**
   * Get delivered emails for a specific recipient.
   */
  getDeliveredEmailsForRecipient(recipient: string): DeliveredEmail[] {
    return this.deliveredEmails.filter((e) => e.recipient === recipient);
  }

  /**
   * Clear all delivered emails (useful for testing).
   */
  clearDeliveredEmails(): void {
    this.deliveredEmails = [];
  }
}

/**
 * Notification service — dispatches notifications via the EventBus.
 *
 * This service listens for domain events (e.g., order:created) and publishes
 * 'notification:requested' events on the EventBus. Channel handlers (email, SMS,
 * push) subscribe to those events and handle delivery independently.
 *
 * The publish/subscribe pattern makes the system extensible: adding a new
 * channel requires only a new handler that subscribes to 'notification:requested',
 * with no changes to this service.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and dispatching notifications
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  NotificationRequestedEvent,
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for notification triggers.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendNotification({
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Dispatch a notification via the EventBus and record it locally.
   */
  private sendNotification(params: {
    channel: string;
    recipient: string;
    subject: string;
    body: string;
  }): void {
    const notification: Notification = {
      id: generateNotificationId(),
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      sentAt: new Date(),
    };
    this.notifications.push(notification);

    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      timestamp: new Date(),
    };
    this.eventBus.emit(event);

    this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);
  }

  /**
   * Send an ad-hoc notification (not triggered by a domain event).
   */
  notify(params: {
    channel: string;
    recipient: string;
    subject: string;
    body: string;
  }): void {
    this.sendNotification(params);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

